#!/usr/bin/env python3
"""Remove JavaScript from an HTML file in place to neutralize XSS.

Strategy: parse with html.parser to locate the exact source spans of
dangerous constructs, then surgically delete/rewrite only those spans in
the original text.  Everything else is left byte-for-byte identical, so
legitimate formatting, tables, headers and safe attributes are preserved.

Removed:
  * <script> ... </script> elements (content included)
  * event-handler attributes (on*)
  * attributes whose value is a javascript:/vbscript: (or data:text/html)
    URI, including entity/whitespace-obfuscated variants
  * style attributes containing javascript: or expression()
"""

import html
import re
import sys
from html.parser import HTMLParser

# --- attribute classification helpers ------------------------------------

URI_ATTRS = {
    "href", "src", "action", "formaction", "xlink:href", "data",
    "poster", "background", "longdesc", "cite", "usemap", "lowsrc",
    "dynsrc", "srcdoc", "ping",
}

# characters browsers strip when resolving a URL scheme
_STRIP = str.maketrans("", "", "\x00\t\n\r\x0b\x0c")


def _norm(value):
    if value is None:
        return ""
    v = html.unescape(value)
    v = v.translate(_STRIP).strip()
    return v.lower()


def _is_js_uri(value):
    v = _norm(value)
    return (
        v.startswith("javascript:")
        or v.startswith("vbscript:")
        or v.startswith("livescript:")
        or v.startswith("mocha:")
        or v.startswith("data:text/html")
    )


def _is_bad_style(value):
    v = _norm(value)
    return "javascript:" in v or "expression(" in v or "vbscript:" in v


def _attr_is_harmful(name, value):
    n = name.lower()
    if n.startswith("on"):
        return True
    if n == "style":
        return _is_bad_style(value)
    if _is_js_uri(value):
        return True
    # meta refresh redirect to a javascript: url
    if n == "content" and ("javascript:" in _norm(value)):
        return True
    return False


def _strip_attr(tagtext, name):
    """Delete every occurrence of attribute *name* from a raw start-tag."""
    pat = re.compile(
        r"\s+" + re.escape(name) +
        r"""(\s*=\s*("[^"]*"|'[^']*'|[^\s"'=<>`]+))?""",
        re.IGNORECASE,
    )
    return pat.sub("", tagtext)


def _clean_tag(tagtext, attrs):
    bad_names = []
    for name, value in attrs:
        if _attr_is_harmful(name, value):
            bad_names.append(name)
    for name in bad_names:
        tagtext = _strip_attr(tagtext, name)
    return tagtext


# --- parser that records edits -------------------------------------------

DANGEROUS_ELEMENTS = {"script"}


class Sanitizer(HTMLParser):
    def __init__(self, text):
        super().__init__(convert_charrefs=True)
        self.text = text
        starts = [0]
        for line in text.split("\n"):
            starts.append(starts[-1] + len(line) + 1)
        self._line_starts = starts
        # list of (start, end, replacement)
        self.edits = []
        self._script_start = None  # offset where an open <script> began

    def _off(self):
        ln, col = self.getpos()
        return self._line_starts[ln - 1] + col

    def handle_starttag(self, tag, attrs):
        off = self._off()
        raw = self.get_starttag_text() or ""
        if tag in DANGEROUS_ELEMENTS:
            # start of an element to drop entirely; wait for the end tag
            self._script_start = off
            return
        cleaned = _clean_tag(raw, attrs)
        if cleaned != raw:
            self.edits.append((off, off + len(raw), cleaned))

    def handle_startendtag(self, tag, attrs):
        off = self._off()
        raw = self.get_starttag_text() or ""
        if tag in DANGEROUS_ELEMENTS:
            self.edits.append((off, off + len(raw), ""))
            return
        cleaned = _clean_tag(raw, attrs)
        if cleaned != raw:
            self.edits.append((off, off + len(raw), cleaned))

    def handle_endtag(self, tag):
        if tag in DANGEROUS_ELEMENTS and self._script_start is not None:
            off = self._off()
            gt = self.text.find(">", off)
            end = gt + 1 if gt != -1 else len(self.text)
            self.edits.append((self._script_start, end, ""))
            self._script_start = None

    def close(self):
        super().close()
        # unterminated <script>: drop to end of document
        if self._script_start is not None:
            self.edits.append((self._script_start, len(self.text), ""))
            self._script_start = None


def sanitize(text):
    parser = Sanitizer(text)
    parser.feed(text)
    parser.close()
    edits = sorted(parser.edits, key=lambda e: e[0])
    # drop edits fully contained in a previous (e.g. attrs inside a script)
    result = text
    covered_end = -1
    kept = []
    for start, end, rep in edits:
        if start < covered_end:
            continue
        kept.append((start, end, rep))
        covered_end = end
    for start, end, rep in reversed(kept):
        result = result[:start] + rep + result[end:]
    return result


def main(argv):
    if len(argv) < 2:
        sys.stderr.write("usage: filter.py <html-file>\n")
        return 2
    path = argv[1]
    with open(path, "rb") as fh:
        data = fh.read()
    text = data.decode("utf-8", "surrogateescape")
    cleaned = sanitize(text)
    with open(path, "wb") as fh:
        fh.write(cleaned.encode("utf-8", "surrogateescape"))
    return 0


if __name__ == "__main__":
    sys.exit(main(sys.argv))

